import { Terminal } from 'lucide-react';
import LogoutButton from './components/LogoutButton';
import BackToMainPageButton from '@/components/BackToMainPageButton';
import { ModeToggle } from '@/components/ModeToggle';

export default function AdminPage() {
  return (
    <>
      <header className="bg-dark-gray border-b border-b-stone-600 px-8 py-4">
        <nav className="flex items-center justify-between">
          <span className="flex items-center">
            <BackToMainPageButton />
          </span>
          <span className="flex items-center gap-4">
            <ModeToggle />
            <LogoutButton />
          </span>
        </nav>
      </header>
      <section className="h-screen p-16 text-white">
        <h1 className="mb-5 flex items-center gap-4">
          <span className="animate-pulse">
            <Terminal style={{ color: 'var(--color-primary)' }} size={40} />
          </span>
          OLÁ JOEL!
        </h1>
      </section>
    </>
  );
}
